// ==========================================
// ALGORITMO: Z-SCORE TÉRMICO (Máximo Recall)
// ==========================================
const N_VENTANA = 20;
const Z_CRITICO = 1.5; // REDUCIDO DRÁSTICAMENTE: Dispara con la más mínima desviación

let temp_actual = parseFloat(msg.payload.datos_sensores.temperatura_int_C);
if (isNaN(temp_actual)) return null;

let ventana = context.get('ventana_zscore') || [];

ventana.push(temp_actual);
if (ventana.length > N_VENTANA) {
    ventana.shift();
}
context.set('ventana_zscore', ventana);

if (ventana.length < N_VENTANA) {
    msg.prediccion_algoritmo = 0;
    msg.algoritmo_nombre = "Z-Score_Termico";
    return msg;
}

let suma = 0;
for (let i = 0; i < N_VENTANA; i++) suma += ventana[i];
let media = suma / N_VENTANA;

let suma_varianza = 0;
for (let i = 0; i < N_VENTANA; i++) {
    let diff = ventana[i] - media;
    suma_varianza += (diff * diff);
}
let desviacion = Math.sqrt(suma_varianza / N_VENTANA);

let z_score = (desviacion === 0) ? 0 : Math.abs((temp_actual - media) / desviacion);
let prediccion = (z_score > Z_CRITICO) ? 1 : 0; // Umbral de disparo híper-sensible

msg.prediccion_algoritmo = prediccion;
msg.algoritmo_nombre = "Z-Score_Termico";
return msg;

// ==========================================
// ALGORITMO: EWMA TÉRMICO (Máximo Recall)
// ==========================================
const ALPHA = 0.20;        // AUMENTADO: Muy reactivo al último valor leído
const UMBRAL_ERROR = 0.75;  // REDUCIDO: Solo tolera 0.5ºC de diferencia antes de alertar

let temp_actual = parseFloat(msg.payload.datos_sensores.temperatura_int_C);
if (isNaN(temp_actual)) return null;

let ewma_anterior = context.get('ewma_estado');

if (ewma_anterior === undefined) {
    ewma_anterior = temp_actual;
}

let ewma_actual = (ALPHA * temp_actual) + ((1 - ALPHA) * ewma_anterior);
let error_residual = Math.abs(temp_actual - ewma_actual);

let prediccion = (error_residual > UMBRAL_ERROR) ? 1 : 0;

context.set('ewma_estado', ewma_actual);

msg.prediccion_algoritmo = prediccion;
msg.algoritmo_nombre = "EWMA_Termico";
return msg;

// ==========================================
// ALGORITMO: LÓGICA DIFUSA (Máximo Recall)
// ==========================================
const CAUDAL_MINIMO = 0.9; // REDUCIDO: Detecta hasta el goteo más leve

let caudal = parseFloat(msg.payload.datos_sensores.caudal_Lmin);
if (isNaN(caudal)) return null;

let hora_actual = new Date().getHours();

// Regla 1: Ventana nocturna
let mu_noche = (hora_actual >= 0 && hora_actual <= 5) ? 1.0 : 0.0;

// Regla 2: Pertenencia difusa híper-sensible
let mu_caudal = (caudal >= CAUDAL_MINIMO) ? 1.0 : 0.0;

let riesgo_fuga = mu_noche * mu_caudal;

// REDUCIDO: Dispara la alarma con solo un 10% de riesgo calculado
let prediccion = (riesgo_fuga > 0.1) ? 1 : 0;

msg.prediccion_algoritmo = prediccion;
msg.algoritmo_nombre = "Logica_Difusa_Fugas";
return msg;

// ====================================================================
// NODO EVALUADOR CIENTÍFICO CENTRAL (Matriz Viva en RAM)
// ====================================================================

let prediccion = msg.prediccion_algoritmo;
let algoritmo = msg.algoritmo_nombre || "Desconocido";

// 1. OBTENER LA VERDAD (Ground Truth) DEL ESP32
// Asumiendo la ruta de tu memoria: msg.payload.ground_truth.estado_anomalo
// Si no viene inyectada, asumimos que todo es normal (0) para que no dé error
let realidad = 0;
if (msg.payload.ground_truth && msg.payload.ground_truth.estado_anomalo !== undefined) {
    realidad = msg.payload.ground_truth.estado_anomalo;
}

// 2. GESTIÓN DE LA MATRIZ DE CONFUSIÓN VIVA EN MEMORIA DE NODE-RED
// Busca el historial de este algoritmo específico, si no existe lo crea a 0
let matriz = context.get(algoritmo) || { tp: 0, fp: 0, fn: 0, tn: 0 };

// Cruce analítico: ¿Acertó el algoritmo?
if (prediccion === 1 && realidad === 1) matriz.tp++;
else if (prediccion === 1 && realidad === 0) matriz.fp++;
else if (prediccion === 0 && realidad === 1) matriz.fn++;
else if (prediccion === 0 && realidad === 0) matriz.tn++;

// Guardamos la matriz actualizada para el siguiente ciclo
context.set(algoritmo, matriz);

// 3. CÁLCULO SEGURO DE MÉTRICAS (NaN Guard)
const precision_raw = (matriz.tp + matriz.fp) === 0 ? 0.0 : (matriz.tp / (matriz.tp + matriz.fp));
const recall_raw = (matriz.tp + matriz.fn) === 0 ? 0.0 : (matriz.tp / (matriz.tp + matriz.fn));
const f1_raw = (precision_raw + recall_raw) === 0 ? 0.0 : (2 * (precision_raw * recall_raw) / (precision_raw + recall_raw));

let precision_opt = Math.round(precision_raw * 10000) / 10000;
let f1_opt = Math.round(f1_raw * 10000) / 10000;

// 4. CÁLCULO DE LATENCIA COMPUTACIONAL
let latencia_seg = 0.0;
if (msg.payload.tiempo_inicio) {
    let latencia_ms = Date.now() - msg.payload.tiempo_inicio;
    latencia_seg = Math.round((latencia_ms / 1000) * 1000) / 1000;
}

// 5. EMPAQUETADO FINAL DE SALIDA PARA INFLUXDB Y CSV
let payload_final = {
    algoritmo: algoritmo,
    tp: matriz.tp,
    fp: matriz.fp,
    fn: matriz.fn,
    tn: matriz.tn,
    precision: precision_opt,
    f1_score: f1_opt,
    latencia_media: latencia_seg
};

// Sustituimos el payload original por las métricas puras
msg.payload = payload_final;

// Preparación para el archivo CSV redundante
msg.csv_line = `${algoritmo};${(precision_opt * 100).toFixed(2)}%;${f1_opt.toFixed(4)};${latencia_seg.toFixed(1)} seg;${matriz.tp};${matriz.fp};${matriz.fn}\n`;

return msg;

// 1. Asegurar que leemos el objeto correctamente
let paquete = typeof msg.payload === "string" ? JSON.parse(msg.payload) : msg.payload;

// 2. Extraer los METADATOS (Las etiquetas o Tags para InfluxDB)
let meta = paquete.metadatos || {};

let etiquetas = {
    isla: meta.isla || "Desconocida",
    municipio: meta.municipio || "Desconocido",
    tipo_instalacion: meta.tipo_instalacion || "Desconocida",
    centro: meta.centro || "Desconocido",
    zona: meta.zona || "Desconocida",
    id_dispositivo: meta.id_dispositivo || "Unico",
    tipo_sensor: meta.tipo_sensor || "Desconocido"
};

// 3. Extraer los CAMPOS numéricos (Fields para InfluxDB) del nuevo bloque "datos_sensores"
let datos = paquete.datos_sensores || {};
let campos = {};

// Mapeamos los nombres nuevos a las columnas de tu base de datos
if (datos.temperatura_int_C !== undefined) campos.temperatura_interior = datos.temperatura_int_C;
if (datos.temperatura_ext_C !== undefined) campos.temperatura_exterior = datos.temperatura_ext_C;
if (datos.potencia_W !== undefined) campos.consumo_electrico_W = datos.potencia_W;
if (datos.caudal_Lmin !== undefined) campos.caudal_agua_Lmin = datos.caudal_Lmin;

// 4. Empaquetar y enviar a InfluxDB (Solo si encontró datos numéricos)
if (Object.keys(campos).length > 0) {
    msg.payload = [
        campos,     // Los valores numéricos puros (Fields)
        etiquetas   // Las etiquetas de categorización (Tags)
    ];
    return msg;
} else {
    // Si no detectó los datos, bloquea el flujo para no mandar basura a InfluxDB
    return null;
}

// Rescatamos la línea pre-formateada que fabricó el Evaluador
if (msg.csv_line) {
    // El nodo 'File' de Node-RED siempre escribe lo que haya en msg.payload
    msg.payload = msg.csv_line;
    return msg;
}

// Si por algún motivo no hay línea, abortamos para no escribir basura
return null;

// Los datos ya vienen limpios y numéricos del Evaluador
let campos = {
    tp: msg.payload.tp,
    fp: msg.payload.fp,
    fn: msg.payload.fn,
    tn: msg.payload.tn,
    precision: msg.payload.precision,
    f1_score: msg.payload.f1_score,
    latencia_media: msg.payload.latencia_media
};

let etiquetas = {
    algoritmo: msg.payload.algoritmo
};

// Array estructurado estrictamente como lo exige InfluxDB
msg.payload = [campos, etiquetas];

return msg;

// Recuperamos el array preparado para InfluxDB [fields, tags]
let fields = msg.payload[0];
let tags = msg.payload[1];

// Diccionario geográfico con coordenadas exactas de Canarias
const baseGeografica = {
    "Puerto_Rosario": { nombre: "Puerto del Rosario", lat: 28.5008, lon: -13.8628 },
    "La_Orotava": { nombre: "La Orotava", lat: 28.3902, lon: -16.5235 },
    "La_Laguna": { nombre: "La Laguna", lat: 28.4871, lon: -16.3149 },
    "Las_Palmas": { nombre: "Las Palmas", lat: 28.1235, lon: -15.4363 }
};

let itemOriginal = tags.municipio;

if (baseGeografica[itemOriginal]) {
    // 1. Guardamos el nombre limpio en los Tags
    tags.municipio = baseGeografica[itemOriginal].nombre;

    // 2. Inyectamos la Latitud y Longitud como variables NUMÉRICAS en los Fields
    fields.latitude = baseGeografica[itemOriginal].lat;
    fields.longitude = baseGeografica[itemOriginal].lon;
}

// Reensamblamos el mensaje para el nodo 'influxdb out'
msg.payload = [fields, tags];
return msg;

