var utc_milisegundos = ahora.getTime() + (ahora.getTimezoneOffset() * 60000);

msg.payload = { "t": utc_milisegundos };
return msg;

// Le decimos al navegador que esto es un archivo descargable
msg.headers = {
    'Content-Type': 'text/csv',
    'Content-Disposition': 'attachment; filename="resultados_tfm.csv"'
};
return msg;
